const fs = require('fs');
const path = require('path');

let sharp;
try {
  sharp = require('sharp');
} catch(e) {
  throw new Error(
    '[FOCUS Blend] sharp module not available. ' +
    'Ensure NODE_FUNCTION_ALLOW_EXTERNAL=* is set when starting n8n. ' +
    'Error: ' + e.message
  );
}

// ── Parameters ──────────────────────────────────────────────────
const params = $('Set Global Parameters').first().json;
const testCardFilter = (params.TestCardFilter || '').trim();

const raw = $input.first().json;
const deck = raw.data !== undefined ? raw.data : raw;

const deckDir = ((deck.Assets && deck.Assets.Directory)
  ? deck.Assets.Directory
  : 'D:/data/cards/Standard').replace(/\//g, path.sep);

const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error('[FOCUS Blend] No Cards found in Deck.json.');
}

// ── Constants ───────────────────────────────────────────────────
const N_STILLS     = 8;          // 8 blended frames
const OUT_SIZE     = 512;        // output resolution
const START_INDEX  = 7;          // numbering starts at 07
const COMFYUI_INPUT = 'D:/ComfyUI_windows_portable/ComfyUI/input';

// ── Filter cards ────────────────────────────────────────────────
const filteredCards = testCardFilter
  ? cardRefs.filter(c => c.Card === testCardFilter)
  : cardRefs;

if (filteredCards.length === 0) {
  throw new Error(
    '[FOCUS Blend] No cards matched filter: ' +
    JSON.stringify(testCardFilter) +
    '. Check that TestCardFilter matches a Card name in Deck.json.'
  );
}

// Ensure ComfyUI input directory exists
const comfyInputDir = COMFYUI_INPUT.replace(/\//g, path.sep);
fs.mkdirSync(comfyInputDir, { recursive: true });

const results = { processed: 0, skipped: 0, failed: 0, cards: [] };

// ── Process each card ───────────────────────────────────────────
for (const cardRef of filteredCards) {
  const cardName = cardRef.Card;
  const cardFilePath = path.join(
    deckDir,
    cardRef.File.replace(/\//g, path.sep)
  );

  // Read card JSON
  let cardRaw;
  try {
    cardRaw = JSON.parse(
      fs.readFileSync(cardFilePath, 'utf8').replace(/^\uFEFF/, '')
    );
  } catch(e) {
    console.warn('[FOCUS Blend] Cannot read card: ' + cardName + ': ' + e.message);
    results.failed++;
    results.cards.push({
      card: cardName,
      status: 'failed',
      reason: 'Cannot read card file: ' + e.message
    });
    continue;
  }

  const card = cardRaw['data.Cards'] || cardRaw;
  const cardDir = (card.Directory || path.join(deckDir, 'Cards'))
    .replace(/\//g, path.sep);

  // Find the upright record
  const uprightRecord = (card.records || []).find(
    r => r.Orientation === 'upright'
  );
  if (!uprightRecord) {
    results.skipped++;
    results.cards.push({
      card: cardName,
      status: 'skipped',
      reason: 'No upright record'
    });
    continue;
  }

  // Get source (CardImage) and target (Image) filenames
  const cardImageName = uprightRecord.Assets && uprightRecord.Assets.CardImage;
  const imageName     = uprightRecord.Assets && uprightRecord.Assets.Image;

  if (!cardImageName) {
    results.skipped++;
    results.cards.push({
      card: cardName,
      status: 'skipped',
      reason: 'No CardImage in upright record Assets'
    });
    continue;
  }
  if (!imageName) {
    results.skipped++;
    results.cards.push({
      card: cardName,
      status: 'skipped',
      reason: 'No Image in upright record Assets'
    });
    continue;
  }

  const cardImagePath = path.join(cardDir, cardImageName);
  const imagePath     = path.join(cardDir, imageName);

  if (!fs.existsSync(cardImagePath)) {
    results.skipped++;
    results.cards.push({
      card: cardName,
      status: 'skipped',
      reason: 'CardImage not found: ' + cardImagePath
    });
    continue;
  }
  if (!fs.existsSync(imagePath)) {
    results.skipped++;
    results.cards.push({
      card: cardName,
      status: 'skipped',
      reason: 'Image not found: ' + imagePath
    });
    continue;
  }

  // Build output filenames: FOCUS_UPRIGHT_Ace_of_Cups_07.png .. _14.png
  const slug = cardName.replace(/[()]/g, '').replace(/\s+/g, '_');
  const stillNames = Array.from({ length: N_STILLS }, (_, i) =>
    'FOCUS_UPRIGHT_' + slug + '_' +
    String(START_INDEX + i).padStart(2, '0') + '.png'
  );
  const stillPaths = stillNames.map(n => path.join(cardDir, n));

  // Skip if all stills already exist
  if (stillPaths.every(p => fs.existsSync(p))) {
    console.warn(
      '[FOCUS Blend] Stills already exist for: ' + cardName + ', updating JSON only.'
    );
    if (!uprightRecord.Assets) uprightRecord.Assets = {};
    const existing = uprightRecord.Assets.FocusUprightT || [];
    // Append without duplicates
    const merged = [...existing.filter(n => !stillNames.includes(n)), ...stillNames];
    uprightRecord.Assets.FocusUprightT = merged;
    fs.writeFileSync(cardFilePath, JSON.stringify(cardRaw, null, 2), 'utf8');
    results.skipped++;
    results.cards.push({
      card: cardName,
      status: 'skipped',
      reason: 'Already generated (JSON updated)',
      stills: stillNames
    });
    continue;
  }

  // ── Generate blended frames ─────────────────────────────────
  try {
    // Load source (CardImage) and target (Image), both resized to OUT_SIZE
    const srcBuf = await sharp(cardImagePath)
      .resize(OUT_SIZE, OUT_SIZE)
      .ensureAlpha(0)       // normalise to 3-channel after resize
      .removeAlpha()
      .raw()
      .toBuffer();

    const tgtBuf = await sharp(imagePath)
      .resize(OUT_SIZE, OUT_SIZE)
      .ensureAlpha(0)
      .removeAlpha()
      .raw()
      .toBuffer();

    if (srcBuf.length !== tgtBuf.length) {
      throw new Error(
        'Buffer size mismatch after resize: src=' + srcBuf.length +
        ' tgt=' + tgtBuf.length
      );
    }

    const channels = 3; // RGB

    for (let i = 0; i < N_STILLS; i++) {
      // t goes from 0.0 (100% CardImage) to 1.0 (100% Image)
      const t = i / (N_STILLS - 1);

      // Per-pixel linear cross-fade
      const blended = Buffer.alloc(srcBuf.length);
      for (let j = 0; j < srcBuf.length; j++) {
        blended[j] = Math.round(srcBuf[j] * (1 - t) + tgtBuf[j] * t);
      }

      // Write to card directory
      await sharp(blended, {
        raw: { width: OUT_SIZE, height: OUT_SIZE, channels }
      })
        .png()
        .toFile(stillPaths[i]);

      // Copy to ComfyUI input directory for testing
      const comfyDest = path.join(comfyInputDir, stillNames[i]);
      fs.copyFileSync(stillPaths[i], comfyDest);
    }

    // ── Update card JSON ────────────────────────────────────────
    if (!uprightRecord.Assets) uprightRecord.Assets = {};
    const existing = uprightRecord.Assets.FocusUprightT || [];
    // Append new names, avoiding duplicates
    const merged = [...existing.filter(n => !stillNames.includes(n)), ...stillNames];
    uprightRecord.Assets.FocusUprightT = merged;
    fs.writeFileSync(cardFilePath, JSON.stringify(cardRaw, null, 2), 'utf8');

    results.processed++;
    results.cards.push({
      card: cardName,
      status: 'generated',
      stills: stillNames,
      blendRange: '0.0 (CardImage) → 1.0 (Image)',
      outputDir: cardDir,
      comfyInputDir: COMFYUI_INPUT,
      focusUprightTTotal: merged.length
    });

  } catch(e) {
    console.warn('[FOCUS Blend] Error processing ' + cardName + ': ' + e.message);
    results.failed++;
    results.cards.push({
      card: cardName,
      status: 'failed',
      reason: 'Processing error: ' + e.message
    });
  }
}

if (results.processed === 0 && results.failed === 0 && results.skipped === 0) {
  throw new Error(
    '[FOCUS Blend] No cards processed. ' +
    'Check TestCardFilter and Deck.json Cards array.'
  );
}

return [{ json: results }];
